def refresh_entity(url, entity, options) do
  force_fetch = Keyword.get(options, :force, false)

  if force_fetch and not are_same_origin?(url, Endpoint.url()) do
    Logger.debug("Entity is external and we want a force fetch")

    case Fetcher.fetch_and_update(url, options) do
      {:ok, _activity, entity} -> {:ok, entity}
      {:error, :http_gone} -> {:error, :http_gone, entity}
      {:error, :http_not_found} -> {:error, :http_not_found, entity}
      {:error, err} -> {:error, err}
    end
  else
    {:ok, entity}
  end
end

def init(args) do
  {:ok, args}
end

def queue_pop([%{item: element} | queue]) do
  {element, queue}
end

def get_remove_object(object) do
  case object |> Utils.get_url() |> ActivityPub.fetch_object_from_url() do
    {:ok, %Member{actor: %Actor{id: person_id}}} -> {:ok, person_id}
    _ -> {:error, :remove_object_not_found}
  end
end

def remaining_attendee_capacity(
      %{maximum_attendee_capacity: maximum_attendee_capacity},
      participant_count
    )
    when is_integer(maximum_attendee_capacity) and maximum_attendee_capacity > 0 do
  maximum_attendee_capacity - participant_count
end
def remaining_attendee_capacity(
      %{maximum_attendee_capacity: _},
      _participant_count
    ) do
  nil
end

def prepare_public_key(public_key_code) do
  case :public_key.pem_decode(public_key_code) do
    [public_key_entry] -> {:ok, :public_key.pem_entry_decode(public_key_entry)}
    _ -> {:error, :pem_decode_error}
  end
end

def validate_json_response(body, headers) do
  cond do
    !content_type_matches?(headers, "application/json") -> {:error, :bad_content_type}
    !is_map(body) -> {:error, :body_not_json}
    true -> {:ok, body}
  end
end

def get_scopes do
  @global_scope |> Map.values() |> Enum.concat() |> Enum.concat([:read, :write])
end

def get_category_statistics(_parent, _params, _context) do
  {:ok, StatisticsModule.category_statistics()}
end

def lowercase_domain(email) when is_binary(email) do
  case split_email(email) do
    [user_part, domain_part] -> {:ok, "#{user_part}@#{String.downcase(domain_part)}"}
    _ -> {:error, :invalid_email}
  end
end
def lowercase_domain(_) do
  {:error, :invalid_email}
end

def cachex_spec(name, limit, default, interval, fallback \\ nil) do
  %{
    id: String.to_atom("cache_#{to_string(name)}"),
    start:
      {Cachex, :start_link,
       [
         name,
         Keyword.merge(
           cachex_options(limit, default, interval),
           fallback_options(fallback)
         )
       ]}
  }
end

