    when is_integer(duration) and is_integer(max) and max > 0 do
  if duration > max do
    {:error, :read_duration_exceeded}
  else
    {:ok, {duration, :erlang.system_time(:millisecond)}}
  end
end
def check_read_duration(_, _) do
  {:ok, {:no_duration_limit, :no_duration_limit}}
end

